+	}
+
+	client, err := NewClient("klaude-deploy", b.config.KlaudeDeployPath, args...)
+	if err != nil {
+		return err
+	}
+
+	if err := client.Start(ctx); err != nil {
+		return err
+	}
+
+	b.mu.Lock()
+	b.deployClient = client
+	b.mu.Unlock()
+
+	return nil
+}
