+package mcp
+
+import (
+	"bufio"
+	"context"
+	"encoding/json"
+	"fmt"
+	"io"
+	"os/exec"
+	"sync"
+	"sync/atomic"
+)
+
+// Client is a generic MCP client that communicates with an MCP server via stdio
+type Client struct {
+	name    string
+	cmd     *exec.Cmd
+	stdin   io.WriteCloser
+	stdout  *bufio.Reader
+	stderr  io.ReadCloser
+	mu      sync.Mutex
+	idSeq   atomic.Int64
+	pending map[interface{}]chan *Response
+	tools   []Tool
+	ready   bool
+}
+
+// JSON-RPC types
+type Request struct {
+	JSONRPC string      `json:"jsonrpc"`
+	ID      interface{} `json:"id,omitempty"`
+	Method  string      `json:"method"`
+	Params  interface{} `json:"params,omitempty"`
+}
+
+type Response struct {
+	JSONRPC string          `json:"jsonrpc"`
+	ID      interface{}     `json:"id,omitempty"`
+	Result  json.RawMessage `json:"result,omitempty"`
+	Error   *Error          `json:"error,omitempty"`
+}
+
+type Error struct {
+	Code    int         `json:"code"`
+	Message string      `json:"message"`
+	Data    interface{} `json:"data,omitempty"`
+}
+
+// MCP types
+type Tool struct {
+	Name        string      `json:"name"`
+	Description string      `json:"description"`
+	InputSchema InputSchema `json:"inputSchema"`
+}
+
+type InputSchema struct {
+	Type       string              `json:"type"`
+	Properties map[string]Property `json:"properties,omitempty"`
+	Required   []string            `json:"required,omitempty"`
+}
+
+type Property struct {
+	Type        string   `json:"type"`
+	Description string   `json:"description,omitempty"`
+	Enum        []string `json:"enum,omitempty"`
+}
+
+type InitializeParams struct {
+	ProtocolVersion string     `json:"protocolVersion"`
+	Capabilities    struct{}   `json:"capabilities"`
+	ClientInfo      ClientInfo `json:"clientInfo"`
+}
+
+type ClientInfo struct {
+	Name    string `json:"name"`
+	Version string `json:"version"`
+}
+
+type InitializeResult struct {
+	ProtocolVersion string       `json:"protocolVersion"`
+	Capabilities    Capabilities `json:"capabilities"`
+	ServerInfo      ServerInfo   `json:"serverInfo"`
+}
+
+type Capabilities struct {
+	Tools *ToolsCapability `json:"tools,omitempty"`
+}
+
+type ToolsCapability struct {
+	ListChanged bool `json:"listChanged,omitempty"`
+}
+
+type ServerInfo struct {
+	Name    string `json:"name"`
+	Version string `json:"version"`
+}
+
+type ToolsListResult struct {
+	Tools []Tool `json:"tools"`
+}
+
+type CallToolParams struct {
+	Name      string                 `json:"name"`
+	Arguments map[string]interface{} `json:"arguments,omitempty"`
+}
+
+type CallToolResult struct {
+	Content []ContentItem `json:"content"`
+	IsError bool          `json:"isError,omitempty"`
+}
+
+type ContentItem struct {
+	Type string `json:"type"`
+	Text string `json:"text,omitempty"`
+}
+
+// NewClient creates a new MCP client for the given binary
+func NewClient(name, binaryPath string, args ...string) (*Client, error) {
+	cmd := exec.Command(binaryPath, args...)
+
+	stdin, err := cmd.StdinPipe()
+	if err != nil {
+		return nil, fmt.Errorf("failed to create stdin pipe: %w", err)
+	}
+
+	stdout, err := cmd.StdoutPipe()
+	if err != nil {
+		return nil, fmt.Errorf("failed to create stdout pipe: %w", err)
+	}
+
+	stderr, err := cmd.StderrPipe()
+	if err != nil {
+		return nil, fmt.Errorf("failed to create stderr pipe: %w", err)
+	}
+
+	client := &Client{
+		name:    name,
+		cmd:     cmd,
+		stdin:   stdin,
+		stdout:  bufio.NewReader(stdout),
+		stderr:  stderr,
+		pending: make(map[interface{}]chan *Response),
+	}
+
+	return client, nil
+}
+
+// Start starts the MCP server process and initializes the connection
+func (c *Client) Start(ctx context.Context) error {
+	if err := c.cmd.Start(); err != nil {
+		return fmt.Errorf("failed to start %s: %w", c.name, err)
+	}
+
+	// Start reading responses
+	go c.readResponses()
+
+	// Initialize the connection
+	if err := c.initialize(ctx); err != nil {
+		return fmt.Errorf("failed to initialize %s: %w", c.name, err)
+	}
+
+	// Get available tools
+	if err := c.listTools(ctx); err != nil {
+		return fmt.Errorf("failed to list tools from %s: %w", c.name, err)
+	}
+
+	c.ready = true
+	return nil
+}
+
+// Stop stops the MCP server process
+func (c *Client) Stop() error {
+	if c.cmd.Process != nil {
+		return c.cmd.Process.Kill()
+	}
+	return nil
+}
+
+// IsReady returns whether the client is ready to accept requests
+func (c *Client) IsReady() bool {
+	return c.ready
+}
+
+// Tools returns the list of available tools
+func (c *Client) Tools() []Tool {
+	return c.tools
+}
+
+// CallTool invokes a tool on the MCP server
+func (c *Client) CallTool(ctx context.Context, name string, args map[string]interface{}) (*CallToolResult, error) {
+	if !c.ready {
+		return nil, fmt.Errorf("client not ready")
+	}
+
+	params := CallToolParams{
+		Name:      name,
+		Arguments: args,
+	}
+
+	result, err := c.call(ctx, "tools/call", params)
+	if err != nil {
+		return nil, err
+	}
+
+	var toolResult CallToolResult
+	if err := json.Unmarshal(result, &toolResult); err != nil {
+		return nil, fmt.Errorf("failed to parse tool result: %w", err)
+	}
+
+	return &toolResult, nil
+}
+
+func (c *Client) initialize(ctx context.Context) error {
+	params := InitializeParams{
+		ProtocolVersion: "2024-11-05",
+		ClientInfo: ClientInfo{
+			Name:    "kubestellar-console",
+			Version: "0.1.0",
+		},
+	}
+
+	result, err := c.call(ctx, "initialize", params)
+	if err != nil {
+		return err
+	}
+
+	var initResult InitializeResult
+	if err := json.Unmarshal(result, &initResult); err != nil {
+		return fmt.Errorf("failed to parse initialize result: %w", err)
+	}
+
+	// Send initialized notification
+	c.notify("notifications/initialized", nil)
+
+	return nil
+}
+
+func (c *Client) listTools(ctx context.Context) error {
+	result, err := c.call(ctx, "tools/list", nil)
+	if err != nil {
+		return err
+	}
+
+	var toolsResult ToolsListResult
+	if err := json.Unmarshal(result, &toolsResult); err != nil {
+		return fmt.Errorf("failed to parse tools list: %w", err)
+	}
+
+	c.tools = toolsResult.Tools
+	return nil
+}
+
+func (c *Client) call(ctx context.Context, method string, params interface{}) (json.RawMessage, error) {
+	id := c.idSeq.Add(1)
+
+	req := Request{
+		JSONRPC: "2.0",
+		ID:      id,
+		Method:  method,
+		Params:  params,
+	}
+
+	respCh := make(chan *Response, 1)
+	c.mu.Lock()
+	c.pending[id] = respCh
+	c.mu.Unlock()
+
+	defer func() {
+		c.mu.Lock()
+		delete(c.pending, id)
+		c.mu.Unlock()
+	}()
+
+	if err := c.send(req); err != nil {
+		return nil, err
+	}
+
+	select {
+	case <-ctx.Done():
+		return nil, ctx.Err()
+	case resp := <-respCh:
+		if resp.Error != nil {
+			return nil, fmt.Errorf("RPC error %d: %s", resp.Error.Code, resp.Error.Message)
+		}
+		return resp.Result, nil
+	}
+}
+
+func (c *Client) notify(method string, params interface{}) error {
+	req := Request{
+		JSONRPC: "2.0",
+		Method:  method,
+		Params:  params,
+	}
+	return c.send(req)
+}
+
+func (c *Client) send(req Request) error {
+	c.mu.Lock()
+	defer c.mu.Unlock()
+
+	data, err := json.Marshal(req)
+	if err != nil {
+		return fmt.Errorf("failed to marshal request: %w", err)
+	}
+
+	data = append(data, '\n')
+	if _, err := c.stdin.Write(data); err != nil {
+		return fmt.Errorf("failed to send request: %w", err)
+	}
+
+	return nil
+}
+
+func (c *Client) readResponses() {
+	for {
+		line, err := c.stdout.ReadBytes('\n')
+		if err != nil {
+			if err != io.EOF {
+				fmt.Printf("[%s] read error: %v\n", c.name, err)
+			}
+			return
+		}
+
+		var resp Response
+		if err := json.Unmarshal(line, &resp); err != nil {
+			continue
+		}
+
+		// Route response to waiting caller
+		if resp.ID != nil {
+			c.mu.Lock()
+			if ch, ok := c.pending[resp.ID]; ok {
+				ch <- &resp
+			}
+			c.mu.Unlock()
+		}
+	}
